    func card(
        _ id: String,
        _ subject: String,
        _ topic: String,
        _ prompt: String,
        _ hint: String,
        _ options: [String],
        _ correctOptionIDs: [String]
    ) -> QuestionCard {
        QuestionCard(
            id: id,
            subject: subject,
            topic: topic,
            prompt: prompt,
            hint: hint,
            options: options.enumerated().map { index, value in
                AnswerOption(id: "\(index + 1)", text: value)
            },
            correctOptionIDs: Set(correctOptionIDs)
        )
    }
